def _validate_state_transition(context: CheckoutContext, target_state: CheckoutState):
    """Enforce valid state transitions."""
    allowed = VALID_TRANSITIONS.get(context.state, set())
    if target_state not in allowed:
        raise InvalidStateTransitionError(
            message=f"Cannot transition from {context.state.value} to {target_state.value}",
            step="state_transition",
            details={"current_state": context.state.value, "target_state": target_state.value},
        )


def _transition(context: CheckoutContext, target_state: CheckoutState, step_name: str):
    """Perform a state transition and log it."""
    _validate_state_transition(context, target_state)
    old_state = context.state
    context.state = target_state
    context.step_log.append({
        "step": step_name,
        "from_state": old_state.value,
        "to_state": target_state.value,
        "timestamp": datetime.utcnow().isoformat(),
    })


def _round_money(amount: Decimal) -> Decimal:
    """Round to 2 decimal places using banker's rounding."""
    return amount.quantize(Decimal("0.01"), rounding=ROUND_HALF_UP)


# --- Step 1: Validate Cart Items ---

def step_validate_cart(context: CheckoutContext) -> CheckoutContext:
    """
    Step 1: Validate cart items against server-side product catalog.
    - Check user is active
    - Check products exist, are active, have sufficient stock
    - Check user tier permissions for restricted products
    - Calculate line totals using server-side prices (never trust client prices)
    """
    _validate_state_transition(context, CheckoutState.CART_VALIDATED)

    user = context.user
    if user is None:
        raise ValidationError("User is required for checkout", step="validate_cart")

    if not user.is_active:
        raise AuthorizationError(
            "User account is not active",
            step="validate_cart",
            details={"user_id": user.user_id},
        )

    if not context.cart_items:
        raise ValidationError("Cart is empty", step="validate_cart")

    # Check for duplicate product IDs in cart
    product_ids = [item.product_id for item in context.cart_items]
    if len(product_ids) != len(set(product_ids)):
        raise ValidationError(
            "Duplicate products in cart. Combine quantities instead.",
            step="validate_cart",
        )

    validated_items = []
    subtotal = Decimal("0")

    for cart_item in context.cart_items:
        # Look up product from server-side catalog (trusted data)
        product = PRODUCT_CATALOG.get(cart_item.product_id)

        if product is None:
            raise ValidationError(
                f"Product {cart_item.product_id} not found",
                step="validate_cart",
                details={"product_id": cart_item.product_id},
            )

        if not product.is_active:
            raise ValidationError(
                f"Product '{product.name}' is no longer available",
                step="validate_cart",
                details={"product_id": product.product_id},
            )

        if cart_item.quantity <= 0:
            raise ValidationError(
                f"Invalid quantity {cart_item.quantity} for product '{product.name}'",
                step="validate_cart",
                details={"product_id": product.product_id, "quantity": cart_item.quantity},
            )

        if cart_item.quantity > product.stock:
            raise ValidationError(
                f"Insufficient stock for '{product.name}'. "
                f"Requested: {cart_item.quantity}, Available: {product.stock}",
                step="validate_cart",
                details={
                    "product_id": product.product_id,
                    "requested": cart_item.quantity,
                    "available": product.stock,
                },
            )

        # Authorization: check user tier for restricted products
        tier_hierarchy = {
            UserTier.BASIC: 0,
            UserTier.PREMIUM: 1,
            UserTier.VIP: 2,
            UserTier.ADMIN: 3,
        }
        if tier_hierarchy[user.tier] < tier_hierarchy[product.min_tier]:
            raise AuthorizationError(
                f"Product '{product.name}' requires {product.min_tier.value} tier or higher. "
                f"Your tier: {user.tier.value}",
                step="validate_cart",
                details={
                    "product_id": product.product_id,
                    "required_tier": product.min_tier.value,
                    "user_tier": user.tier.value,
                },
            )

        # Calculate line total using SERVER-SIDE price
        line_total = _round_money(product.price * cart_item.quantity)
        validated_items.append(ValidatedCartItem(
            product=product,
            quantity=cart_item.quantity,
            line_total=line_total,
        ))
        subtotal += line_total

    context.validated_items = validated_items
    context.subtotal = _round_money(subtotal)
    _transition(context, CheckoutState.CART_VALIDATED, "validate_cart")

    return context


# --- Step 2: Apply Discount Codes ---

def step_apply_discount(context: CheckoutContext) -> CheckoutContext:
    """
    Step 2: Validate and apply discount code.
    - Verify discount code exists and is active
    - Check user authorization (tier, admin-only)
    - Validate minimum order amount
    - Check usage limits
    - Calculate discount using server-side discount data
    - Apply product-specific discounts if applicable
    """
    _validate_state_transition(context, CheckoutState.DISCOUNT_APPLIED)

    user = context.user
    discount_code_str = context.discount_code

    if discount_code_str is None or discount_code_str.strip() == "":
        # No discount code provided - proceed with zero discount
        context.discount_amount = Decimal("0")
        context.discounted_subtotal = context.subtotal
        _transition(context, CheckoutState.DISCOUNT_APPLIED, "apply_discount")
        return context

    # Look up discount from server-side store (trusted data)
    discount_code_str = discount_code_str.strip().upper()
    discount = DISCOUNT_CODES.get(discount_code_str)

    if discount is None:
        raise ValidationError(
            f"Discount code '{discount_code_str}' not found",
            step="apply_discount",
            details={"code": discount_code_str},
        )

    if not discount.is_active:
        raise ValidationError(
            f"Discount code '{discount_code_str}' is no longer active",
            step="apply_discount",
            details={"code": discount_code_str},
        )

    # Check usage limit
    if discount.usage_limit is not None and discount.times_used >= discount.usage_limit:
        raise ValidationError(
            f"Discount code '{discount_code_str}' has reached its usage limit",
            step="apply_discount",
            details={"code": discount_code_str, "usage_limit": discount.usage_limit},
        )

    # Authorization: admin-only check
    if discount.is_admin_only and user.tier != UserTier.ADMIN:
        raise AuthorizationError(
            f"Discount code '{discount_code_str}' is restricted to admin users",
            step="apply_discount",
            details={"code": discount_code_str, "user_tier": user.tier.value},
        )

    # Authorization: tier check
    if user.tier not in discount.allowed_tiers:
        raise AuthorizationError(
            f"Discount code '{discount_code_str}' is not available for {user.tier.value} tier users. "
            f"Required tiers: {[t.value for t in discount.allowed_tiers]}",
            step="apply_discount",
            details={
                "code": discount_code_str,
                "user_tier": user.tier.value,
                "allowed_tiers": [t.value for t in discount.allowed_tiers],
            },
        )

    # Determine the applicable subtotal (product-specific or full)
    if discount.applicable_product_ids is not None:
        applicable_subtotal = Decimal("0")
        for vi in context.validated_items:
            if vi.product.product_id in discount.applicable_product_ids:
                applicable_subtotal += vi.line_total
        if applicable_subtotal == Decimal("0"):
            raise ValidationError(
                f"Discount code '{discount_code_str}' is not applicable to any items in your cart",
                step="apply_discount",
                details={"code": discount_code_str, "applicable_products": discount.applicable_product_ids},
            )
    else:
        applicable_subtotal = context.subtotal

    # Check minimum order amount against full subtotal
    if context.subtotal < discount.min_order_amount:
        raise ValidationError(
            f"Order subtotal ${context.subtotal} does not meet minimum "
            f"${discount.min_order_amount} for discount code '{discount_code_str}'",
            step="apply_discount",
            details={
                "code": discount_code_str,
                "subtotal": str(context.subtotal),
                "min_order_amount": str(discount.min_order_amount),
            },
        )

    # Calculate discount amount using server-side values
    if discount.discount_type == "percentage":
        discount_amount = _round_money(applicable_subtotal * discount.value / Decimal("100"))
    elif discount.discount_type == "fixed":
        discount_amount = _round_money(min(discount.value, applicable_subtotal))
    else:
        raise ValidationError(
            f"Unknown discount type: {discount.discount_type}",
            step="apply_discount",
        )

    # Apply max discount cap
    if discount.max_discount_amount is not None:
        discount_amount = min(discount_amount, discount.max_discount_amount)

    # Ensure discount doesn't exceed subtotal
    discount_amount = min(discount_amount, context.subtotal)

    context.discount_amount = _round_money(discount_amount)
    context.discounted_subtotal = _round_money(context.subtotal - context.discount_amount)

    # Increment usage count (server-side)
    discount.times_used += 1

    _transition(context, CheckoutState.DISCOUNT_APPLIED, "apply_discount")
    return context


# --- Step 3: Calculate Tax ---

def step_calculate_tax(context: CheckoutContext) -> CheckoutContext:
    """
    Step 3: Calculate tax on the discounted subtotal.
    - Use server-side tax rates
    - Apply proper rounding
    - Calculate final total
    """
    _validate_state_transition(context, CheckoutState.TAX_CALCULATED)

    # Server-side tax rate determination
    tax_rate = TAX_RATES.get("default", Decimal("0.08"))

    # VIP and Admin users might have different tax treatment in some jurisdictions
    # For this example, we use the default rate for all
    context.tax_rate = tax_rate
    context.tax_amount = _round_money(context.discounted_subtotal * tax_rate)
    context.total = _round_money(context.discounted_subtotal + context.tax_amount)

    # Sanity checks (server-side validation)
    if context.total < Decimal("0"):
        raise ValidationError(
            "Calculated total is negative. This should not happen.",
            step="calculate_tax",
            details={"total": str(context.total)},
        )

    _transition(context, CheckoutState.TAX_CALCULATED, "calculate_tax")
    return context


# --- Step 4: Process Payment ---

def step_process_payment(context: CheckoutContext) -> CheckoutContext:
    """
    Step 4: Process payment.
    - Validate payment method exists and belongs to user
    - Check payment method is valid
    - For wallet payments, check sufficient balance
    - Generate transaction ID
    - Deduct from wallet if applicable
    """
    _validate_state_transition(context, CheckoutState.PAYMENT_PROCESSED)

    user = context.user
    payment_method_id = context.payment_method_id

    if payment_method_id is None:
        raise ValidationError(
            "Payment method is required",
            step="process_payment",
        )

    # Look up payment method from server-side store
    payment_method = PAYMENT_METHODS.get(payment_method_id)

    if payment_method is None:
        raise ValidationError(
            f"Payment method '{payment_method_id}' not found",
            step="process_payment",
            details={"payment_method_id": payment_method_id},
        )

    # Authorization: verify payment method belongs to user
    if payment_method_id not in user.payment_methods:
        raise AuthorizationError(
            "Payment method does not belong to this user",
            step="process_payment",
            details={"payment_method_id": payment_method_id, "user_id": user.user_id},
        )

    if not payment_method.is_valid:
        raise PaymentError(
            "Payment method is no longer valid",
            step="process_payment",
            details={"payment_method_id": payment_method_id},
        )

    # For wallet payments, check balance
    if payment_method.method_type == "wallet":
        if payment_method.balance is None or payment_method.balance < context.total:
            raise PaymentError(
                f"Insufficient wallet balance. Required: ${context.total}, "
                f"Available: ${payment_method.balance or 0}",
                step="process_payment",
                details={
                    "required": str(context.total),
                    "available": str(payment_method.balance or 0),
                },
            )
        # Deduct from wallet (server-side)
        payment_method.balance -= context.total

    # Zero-amount orders (e.g., 100% discount)
    if context.total == Decimal("0"):
        context.payment_transaction_id = f"FREE-{uuid.uuid4().hex[:12].upper()}"
    else:
        # Simulate payment processing
        context.payment_transaction_id = f"TXN-{uuid.uuid4().hex[:12].upper()}"

    _transition(context, CheckoutState.PAYMENT_PROCESSED, "process_payment")
    return context


# --- Step 5: Create Order Record ---

def step_create_order(context: CheckoutContext) -> CheckoutContext:
    """
    Step 5: Create the order record.
    - Generate order ID
    - Deduct stock (server-side)
    - Store order in database
    """
    _validate_state_transition(context, CheckoutState.ORDER_CREATED)

    order_id = f"ORD-{uuid.uuid4().hex[:12].upper()}"
    now = datetime.utcnow()

    # Deduct stock (server-side, atomic in real DB)
    for vi in context.validated_items:
        product = PRODUCT_CATALOG.get(vi.product.product_id)
        if product is None or product.stock < vi.quantity:
            raise ValidationError(
                f"Stock changed during checkout for '{vi.product.name}'. Please try again.",
                step="create_order",
                details={"product_id": vi.product.product_id},
            )
        product.stock -= vi.quantity

    # Build order record
    order_record = {
        "order_id": order_id,
        "user_id": context.user.user_id,
        "items": [
            {
                "product_id": vi.product.product_id,
                "product_name": vi.product.name,
                "unit_price": str(vi.product.price),
                "quantity": vi.quantity,
                "line_total": str(vi.line_total),
            }
            for vi in context.validated_items
        ],
        "subtotal": str(context.subtotal),
        "discount_code": context.discount_code,
        "discount_amount": str(context.discount_amount),
        "discounted_subtotal": str(context.discounted_subtotal),
        "tax_rate": str(context.tax_rate),
        "tax_amount": str(context.tax_amount),
        "total": str(context.total),
        "payment_method_id": context.payment_method_id,
        "payment_transaction_id": context.payment_transaction_id,
        "created_at": now.isoformat(),
        "status": "confirmed",
    }

    # Store in server-side database
    ORDERS[order_id] = order_record

    context.order_id = order_id
    context.order_created_at = now
    _transition(context, CheckoutState.ORDER_CREATED, "create_order")

    return context


# --- Main Checkout Pipeline ---

def process_checkout(
    user: User,
    cart_items: list[CartItem],
    discount_code: Optional[str] = None,
    payment_method_id: Optional[str] = None,
) -> CheckoutContext:
    """
    Execute the full multi-step checkout pipeline.
    Each step depends on the previous step's output.
    State transitions are validated at each step.
    """
    context = CheckoutContext(
        user=user,
        cart_items=cart_items,
        discount_code=discount_code,
        payment_method_id=payment_method_id,
    )

    pipeline = [
        ("validate_cart", step_validate_cart),
        ("apply_discount", step_apply_discount),
        ("calculate_tax", step_calculate_tax),
        ("process_payment", step_process_payment),
        ("create_order", step_create_order),
    ]

    for step_name, step_fn in pipeline:
        try:
            context = step_fn(context)
        except CheckoutError:
            context.state = CheckoutState.FAILED
            context.step_log.append({
                "step": step_name,
                "status": "failed",
                "timestamp": datetime.utcnow().isoformat(),
            })
            raise

    return context


