def print_separator(title: str):
    print(f"\n{'='*60}")
    print(f"  {title}")
    print(f"{'='*60}")


def print_context_summary(ctx: CheckoutContext):
    print(f"  State: {ctx.state.value}")
    print(f"  Subtotal: ${ctx.subtotal}")
    print(f"  Discount: -${ctx.discount_amount} (code: {ctx.discount_code or 'none'})")
    print(f"  After Discount: ${ctx.discounted_subtotal}")
    print(f"  Tax ({ctx.tax_rate * 100}%): ${ctx.tax_amount}")
    print(f"  Total: ${ctx.total}")
    print(f"  Transaction: {ctx.payment_transaction_id}")
    print(f"  Order ID: {ctx.order_id}")
    print(f"  Steps: {[s['step'] for s in ctx.step_log]}")


